  ('pukao-1fb53453-moex-00014', 'pukao-1fb53453', 'pukao-1fb53453-moex-113-6948958a', 'sub-pukao-1fb53453-01', NULL, 'single_choice', '有關消費者剩餘（consumersurplus），下列何者正確？', '["消費者願意付出最高價格超出實際支付價格的差額", "消費者願意付出最高價格超出廠商要求最低供給價格的差額", "消費者願意付出最低價格減去實際支付價格的差額", "消費者願意付出最低價格超出廠商要求最低供給價格的差額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:52+00:00", "source_pdf_sha1": "95c3429fd606", "answer_pdf_sha1": "f2e9808a87be", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "423", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財經廉政"}'::jsonb, NULL),
